const fs = require('fs');
const path = '/data/onboarding_state.json';
let state = {started: false, spotify_connected: false, survey_day: 0, questions_asked: [], questions_answered: [], completed: false};
try { state = JSON.parse(fs.readFileSync(path, 'utf8')); } catch(e) {}
if (state.completed) {
  return [{json: {skip: true, message: 'Onboarding already complete'}}];
}
return [{json: {skip: false, state}}];

const crypto = require('crypto');
// Generate PKCE code_verifier (43-128 chars, URL-safe)
const verifier = crypto.randomBytes(64).toString('base64url').slice(0, 96);
// code_challenge = BASE64URL(SHA256(verifier))
const challenge = crypto.createHash('sha256').update(verifier).digest('base64url');
const clientId = $env.SPOTIFY_CLIENT_ID;
const redirectUri = encodeURIComponent($env.SPOTIFY_REDIRECT_URI);
const scopes = encodeURIComponent('user-follow-read user-read-recently-played user-library-read');
const authUrl = `https://accounts.spotify.com/authorize?response_type=code&client_id=${clientId}&scope=${scopes}&redirect_uri=${redirectUri}&code_challenge_method=S256&code_challenge=${challenge}`;
// Store verifier for later token exchange
const fs = require('fs');
fs.writeFileSync('/data/spotify_pkce_state.json', JSON.stringify({verifier, challenge}), {mode: 0o600});
return [{json: {authUrl, verifier, challenge}}];

