const fs = require('fs');
const https = require('https');
const querystring = require('querystring');
const code = $input.first().json.query.code;
const pkceState = JSON.parse(fs.readFileSync('/data/spotify_pkce_state.json', 'utf8'));
const verifier = pkceState.verifier;
const postData = querystring.stringify({
  grant_type: 'authorization_code',
  code: code,
  redirect_uri: $env.SPOTIFY_REDIRECT_URI,
  client_id: $env.SPOTIFY_CLIENT_ID,
  code_verifier: verifier
});
// HTTP request handled by subsequent HTTP Request node
return [{json: {code, verifier, postData}}];

const fs = require('fs');
const tokenData = $input.first().json;
const tokenPath = '/data/spotify_token.json';
fs.writeFileSync(tokenPath, JSON.stringify({
  access_token: tokenData.access_token,
  refresh_token: tokenData.refresh_token,
  token_type: tokenData.token_type,
  expires_in: tokenData.expires_in,
  obtained_at: new Date().toISOString()
}, null, 2), {mode: 0o600});
return [{json: {success: true, access_token: tokenData.access_token}}];

// Lookup RSS URLs via Podcast Index for each show
const crypto = require('crypto');
const shows = $input.first().json.shows?.items || [];
const apiKey = $env.PODCASTINDEX_API_KEY;
const apiSecret = $env.PODCASTINDEX_API_SECRET;
const unixTime = Math.floor(Date.now() / 1000);
const authHash = crypto.createHash('sha1').update(apiKey + apiSecret + unixTime).digest('hex');
// Return shows with auth headers for subsequent requests
const showsToLookup = shows.map(s => ({
  name: s.name,
  spotify_show_id: s.id,
  language: s.languages?.[0] || 'en',
  publisher: s.publisher
}));
return [{json: {shows: showsToLookup, apiKey, authHash, unixTime}}];

const fs = require('fs');
const lookupData = $input.first().json;
const shows = lookupData.shows || [];
// Build known_podcasts entries (RSS lookup would happen per-show in production)
// Here we build the structure; RSS URLs populated by Podcast Index in batch
const profilePath = '/data/user_profile.json';
let profile = JSON.parse(fs.readFileSync(profilePath, 'utf8'));
const existingNames = new Set(profile.known_podcasts.map(p => p.name.toLowerCase()));
for (const show of shows) {
  if (!existingNames.has(show.name.toLowerCase())) {
    profile.known_podcasts.push({
      name: show.name,
      rss_url: null,
      spotify_show_id: show.spotify_show_id,
      language: show.language || 'en',
      priority: 5,
      max_duration_minutes: 90,
      feedback: {
        topic_score: null,
        host_score: null,
        completion_rate: null,
        why_i_like: [],
        episodes_rated: 0,
        quick_likes: 0,
        quick_dislikes: 0
      }
    });
  }
}
profile.last_updated = new Date().toISOString();
fs.writeFileSync(profilePath, JSON.stringify(profile, null, 2));
// Update onboarding state
const statePath = '/data/onboarding_state.json';
const state = JSON.parse(fs.readFileSync(statePath, 'utf8'));
state.spotify_connected = true;
state.started = true;
state.survey_day = 1;
fs.writeFileSync(statePath, JSON.stringify(state, null, 2));
return [{json: {podcasts_imported: shows.length, profile_path: profilePath}}];

const fs = require('fs');
const profile = JSON.parse(fs.readFileSync('/data/user_profile.json', 'utf8'));
const state = JSON.parse(fs.readFileSync('/data/onboarding_state.json', 'utf8'));
const podcasts = profile.known_podcasts;
// Select 3-5 podcasts not yet surveyed for day 1
const surveyed = new Set(state.questions_asked.map(q => q.podcast_name));
const toSurvey = podcasts.filter(p => !surveyed.has(p.name)).slice(0, 4);
const questions = [];
for (const podcast of toSurvey) {
  // Rotate question types
  const types = ['frequency', 'completeness', 'topic_vs_host'];
  const qType = types[questions.length % types.length];
  if (qType === 'frequency') {
    questions.push({
      podcast_name: podcast.name,
      question_type: 'frequency',
      text: `¿Con qué frecuencia escuchas *${podcast.name}*?`,
      buttons: [['Cada episodio', 'freq_every'], ['A veces', 'freq_sometimes'], ['Raramente', 'freq_rarely'], ['Ya no lo escucho', 'freq_never']]
    });
  } else if (qType === 'completeness') {
    questions.push({
      podcast_name: podcast.name,
      question_type: 'completeness',
      text: `Cuando empiezas un episodio de *${podcast.name}*, ¿sueles terminarlo?`,
      buttons: [['Siempre', 'comp_always'], ['La mayoría', 'comp_most'], ['Solo si engancha', 'comp_hooks'], ['Suelo dejarlo', 'comp_drop']]
    });
  } else {
    questions.push({
      podcast_name: podcast.name,
      question_type: 'topic_vs_host',
      text: `¿Qué te atrae más de *${podcast.name}*?`,
      buttons: [['El tema principal', 'attr_topic'], ['El presentador', 'attr_host'], ['Los invitados', 'attr_guests'], ['Todo', 'attr_all']]
    });
  }
}
// Mark as asked
for (const q of questions) {
  state.questions_asked.push({podcast_name: q.podcast_name, question_type: q.question_type, day: state.survey_day});
}
fs.writeFileSync('/data/onboarding_state.json', JSON.stringify(state, null, 2));
return questions.map(q => ({json: q}));

const fs = require('fs');
const callbackData = $input.first().json.callback_query?.data || '';
// Format: survey:{answer_code}:{podcast_name_partial}
const parts = callbackData.split(':');
if (parts[0] !== 'survey' || parts.length < 3) return [{json: {skip: true}}];
const answerCode = parts[1];
const podcastPartial = parts.slice(2).join(':');
const statePath = '/data/onboarding_state.json';
const state = JSON.parse(fs.readFileSync(statePath, 'utf8'));
state.questions_answered.push({answer_code: answerCode, podcast_partial: podcastPartial, answered_at: new Date().toISOString()});
fs.writeFileSync(statePath, JSON.stringify(state, null, 2));
const allAnswered = state.questions_asked.length <= state.questions_answered.length;

// Build Claude payload for profile synthesis
const state = $input.first().json.state || {};
const onboardingPrompt = (() => { try { return require('fs').readFileSync('/prompts/onboarding_system.md','utf8'); } catch(e) { return ''; } })();
const claudePayload = {
  model: "claude-sonnet-4-5",
  max_tokens: 1024,
  system: "Eres un experto en curadur\u00eda de contenidos personales. Analiza las respuestas del onboarding y genera un perfil JSON completo con: topics (lista de temas con pesos 1-10), known_podcasts (feeds RSS conocidos), preferred_duration_minutes, preferred_days, language, discovery_terms.",
  messages: [{role: "user", content: "Analiza estas respuestas del survey: " + JSON.stringify(state.questions_answered || []) + ". Perfil actual: " + JSON.stringify(state.profile || {})}]
};

return [{json: {answer_code: answerCode, podcast_partial: podcastPartial, all_answered: allAnswered, state}}];

const fs = require('fs');
const claudeResponse = $input.first().json;
const content = claudeResponse.content?.[0]?.text || '{}';
let synthesis;
try { synthesis = JSON.parse(content); } catch(e) {
  const match = content.match(/\{[\s\S]*\}/);
  synthesis = match ? JSON.parse(match[0]) : {};
}
const profilePath = '/data/user_profile.json';
const profile = JSON.parse(fs.readFileSync(profilePath, 'utf8'));
// Apply interest weights
if (synthesis.interest_weights) {
  for (const [k, v] of Object.entries(synthesis.interest_weights)) {
    profile.interests[k] = Math.max(1, Math.min(10, v));
  }
}
// Apply host affinities
if (synthesis.host_affinities) {
  for (const [k, v] of Object.entries(synthesis.host_affinities)) {
    profile.host_affinities[k] = Math.max(1, Math.min(10, v));
  }
}
// Apply podcast updates
if (synthesis.podcast_updates) {
  for (const update of synthesis.podcast_updates) {
    const podcast = profile.known_podcasts.find(p => p.name === update.name);
    if (podcast) {
      podcast.priority = Math.max(1, Math.min(10, update.priority));
      podcast.feedback.completion_rate = update.completion_rate;
    }
  }
}
profile.onboarding_complete = true;
profile.last_updated = new Date().toISOString();
fs.writeFileSync(profilePath, JSON.stringify(profile, null, 2));
// Mark onboarding complete
const statePath = '/data/onboarding_state.json';
const state = JSON.parse(fs.readFileSync(statePath, 'utf8'));
state.completed = true;
fs.writeFileSync(statePath, JSON.stringify(state, null, 2));
return [{json: {summary: synthesis.summary_for_user || 'Perfil actualizado.', profile_path: profilePath}}];

